// AI Intake task-generation worker.
// Trigger payload from QC-Manager (utils/n8n triggerWorkflow) arrives under $json.body.
let body = $json.body || $json;
if (body && typeof body.payload === 'string') {
  try { body = JSON.parse(body.payload); } catch (e) {}
}

const userStoryId = body.user_story_id;
if (!userStoryId) {
  // No story to call back to — nothing to do.
  return [];
}

const maxTasks = Math.max(1, Math.min(Number(body.max_tasks) || 8, 20));
let md = String(body.content_markdown || '').trim();
if (!md) md = '(no markdown provided)';
if (md.length > 20000) md = md.slice(0, 19980).trim() + '\n\n...';

return [{
  json: {
    user_story_id: userStoryId,
    project_id: body.project_id || null,
    job_id: body.job_id || null,
    max_tasks: maxTasks,
    callback_url: body.callback_url || '',
    story_markdown: md,
  },
}];

// Parse the MiniMax reply into the QC-Manager task callback contract.
// MiniMax returns { reply: "...", base_resp: { status_code: 0 } }.
const ctx = $('Build prompt').item.json;
const userStoryId = ctx.user_story_id;
const jobId = ctx.job_id;
const maxTasks = ctx.max_tasks || 8;

function fail(msg) {
  return [{ json: { user_story_id: userStoryId, callback: {
    job_id: jobId, status: 'failed', error_message: String(msg).slice(0, 500),
  } } }];
}

let reply = '';
try {
  if ($json.base_resp && $json.base_resp.status_code !== 0) {
    return fail('MiniMax error: ' + JSON.stringify($json.base_resp));
  }
  reply = String($json.reply || '').trim();
} catch (e) { return fail('No reply from model'); }
if (!reply) return fail('Empty reply from model');

// Strip code fences and isolate the JSON array.
let text = reply.replace(/```(?:json)?/gi, '').trim();
const start = text.indexOf('[');
const end = text.lastIndexOf(']');
if (start === -1 || end === -1 || end < start) return fail('Model did not return a JSON array');

let arr;
try { arr = JSON.parse(text.slice(start, end + 1)); }
catch (e) { return fail('Could not parse task JSON: ' + e.message); }
if (!Array.isArray(arr) || arr.length === 0) return fail('Model returned no tasks');

const allowed = { high: 'High', medium: 'Medium', low: 'Low' };
const tasks = arr.slice(0, maxTasks).map((t) => {
  const title = String((t && (t.title || t.task_name || t.name)) || '').trim().slice(0, 120);
  const description = String((t && (t.description || t.notes)) || '').trim();
  const priority = allowed[String((t && t.priority) || '').toLowerCase()] || 'Medium';
  return { task_name: title, title, description, priority };
}).filter((t) => t.title);

if (tasks.length === 0) return fail('No valid tasks after normalization');

return [{ json: { user_story_id: userStoryId, callback: {
  job_id: jobId, status: 'processed', tasks,
} } }];
